import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Doctorprofile() {
  const { doctor_id } = useParams();
  const navigate = useNavigate();

  const [doctor, setDoctor] = useState(null);
  const [availableTimes, setAvailableTimes] = useState([]);

  const [date, setDate] = useState("");
  const [time, setTime] = useState("");

  const [feedbacks, setFeedbacks] = useState([]);
  const [rating, setRating] = useState("");
  const [comment, setComment] = useState("");

  const [popup, setPopup] = useState({ show: false, message: "" });

  // ================= GET DOCTOR =================
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-details/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => {
        setDoctor(data.doctor);
        setAvailableTimes(data.doctor.available_time_slots || []);
      });
  }, [doctor_id]);

  // ================= GET FEEDBACK =================
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => setFeedbacks(data));
  }, [doctor_id]);

  // ================= POPUP =================
  const showPopup = (msg) => {
    setPopup({ show: true, message: msg });
  };

  // ================= BOOK APPOINTMENT =================
  const handleBook = async () => {
    if (!date || !time) return showPopup("Please select date and time");

    const token = localStorage.getItem("token");

    try {
      const res = await fetch("http://127.0.0.1:8000/book-appointment/", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Token ${token}`,
        },
        body: JSON.stringify({
          doctor_id,
          appointment_date: date,
          time_slot: time,
        }),
      });

      const data = await res.json();

      if (res.ok) {
        showPopup("Appointment booked successfully!");
        setTimeout(() => navigate("/myappointments"), 1500);
      } else {
        showPopup(data.error || "Booking failed");
      }
    } catch {
      showPopup("Server error");
    }
  };

  // ================= FEEDBACK =================
  const submitFeedback = () => {
    if (!rating || !comment) return showPopup("Please add rating & comment");

    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
      body: JSON.stringify({ rating, comment }),
    })
      .then((res) => res.json())
      .then((data) => {
        setFeedbacks([data, ...feedbacks]);
        setRating("");
        setComment("");
        showPopup("Review submitted!");
      });
  };

  if (!doctor) return <h2 style={styles.loading}>Loading...</h2>;

  const avg =
    feedbacks.length > 0
      ? (feedbacks.reduce((a, b) => a + b.rating, 0) / feedbacks.length).toFixed(1)
      : 0;

  return (
    <div style={styles.page}>
      <Navbar />

      {/* ================= POPUP ================= */}
      {popup.show && (
        <div style={styles.overlay}>
          <div style={styles.popupCard}>
            <div style={styles.icon}>✔</div>
            <h3>Notification</h3>
            <p>{popup.message}</p>
            <button onClick={() => setPopup({ show: false })} style={styles.btn}>
              OK
            </button>
          </div>
        </div>
      )}

      {/* ================= MAIN CARD ================= */}
      <div style={styles.container}>
        <div style={styles.card}>

          {/* LEFT */}
          <div style={styles.left}>
            <img
              src={doctor.image}
              alt={doctor.name || "Doctor profile"}
              style={styles.image}
            />
            <h3>{doctor.name}</h3>
            <p>{doctor.field}</p>
          </div>

          {/* RIGHT */}
          <div style={styles.right}>

            {/* BOOKING */}
            <div style={styles.section}>
              <h3>Book Appointment</h3>

              <input
                type="date"
                style={styles.input}
                onChange={(e) => setDate(e.target.value)}
              />

              <select
                style={styles.input}
                onChange={(e) => setTime(e.target.value)}
              >
                <option value="">Select Time</option>
                {availableTimes.map((t, i) => (
                  <option key={i}>{t}</option>
                ))}
              </select>

              <button style={styles.primaryBtn} onClick={handleBook}>
                Confirm Booking
              </button>
            </div>

            {/* ================= FEEDBACK ================= */}
            <div style={styles.section}>
              <div style={styles.header}>
                <h3>Patient Reviews</h3>
                <span style={styles.badge}>{avg} ⭐</span>
              </div>

              <select
                style={styles.input}
                onChange={(e) => setRating(e.target.value)}
              >
                <option value="">Select Rating</option>
                <option value="5">⭐⭐⭐⭐⭐</option>
                <option value="4">⭐⭐⭐⭐</option>
                <option value="3">⭐⭐⭐</option>
                <option value="2">⭐⭐</option>
                <option value="1">⭐</option>
              </select>

              <textarea
                style={styles.textarea}
                placeholder="Write your review..."
                value={comment}
                onChange={(e) => setComment(e.target.value)}
              />

              <button style={styles.secondaryBtn} onClick={submitFeedback}>
                Submit Review
              </button>

              {/* REVIEWS */}
              <div style={styles.reviewList}>
                {feedbacks.map((fb) => (
                  <div key={fb.id} style={styles.reviewCard}>
                    <b>{fb.user_name}</b>
                    <div>{fb.rating} ⭐</div>
                    <p>{fb.comment}</p>
                  </div>
                ))}
              </div>
            </div>

          </div>
        </div>
      </div>

      <Footer />
    </div>
  );
}

export default Doctorprofile;

/* ================= STYLES ================= */
const styles = {
  page: { background: "#f4f6f9", minHeight: "100vh" },

  container: {
    display: "flex",
    justifyContent: "center",
    padding: 30,
  },

  card: {
    display: "flex",
    width: 900,
    background: "#fff",
    borderRadius: 15,
    boxShadow: "0 8px 25px rgba(0,0,0,0.1)",
  },

  left: {
    width: "30%",
    textAlign: "center",
    padding: 20,
    borderRight: "1px solid #eee",
  },

  right: {
    width: "70%",
    padding: 20,
  },

  image: {
    width: 120,
    height: 120,
    borderRadius: "50%",
    objectFit: "cover",
  },

  section: {
    marginBottom: 20,
  },

  input: {
    width: "100%",
    padding: 10,
    margin: "6px 0",
    borderRadius: 8,
    border: "1px solid #ddd",
  },

  textarea: {
    width: "100%",
    height: 80,
    padding: 10,
    borderRadius: 8,
    border: "1px solid #ddd",
  },

  primaryBtn: {
    width: "100%",
    padding: 10,
    background: "#2c3e50",
    color: "#fff",
    border: "none",
    borderRadius: 8,
  },

  secondaryBtn: {
    width: "100%",
    padding: 10,
    background: "#16a085",
    color: "#fff",
    border: "none",
    borderRadius: 8,
    marginTop: 8,
  },

  header: {
    display: "flex",
    justifyContent: "space-between",
  },

  badge: {
    background: "#2c3e50",
    color: "#fff",
    padding: "5px 10px",
    borderRadius: 20,
  },

  reviewList: {
    marginTop: 10,
  },

  reviewCard: {
    background: "#f9fafb",
    padding: 10,
    marginTop: 10,
    borderRadius: 10,
  },

  /* POPUP */
  overlay: {
    position: "fixed",
    top: 0,
    left: 0,
    height: "100%",
    width: "100%",
